SELECT COUNT(DISTINCT p.sku) AS cnt
FROM products p
JOIN inventory i ON i.sku=p.sku
JOIN stores s ON s.id=i.store_id
WHERE p.category_id='drain_traps_siphons' AND s.city='Innsbruck' AND s.status='open' AND i.available_today>0;
SELECT DISTINCT p.path
FROM products p
JOIN inventory i ON i.sku=p.sku
JOIN stores s ON s.id=i.store_id
WHERE p.category_id='drain_traps_siphons' AND s.city='Innsbruck' AND s.status='open' AND i.available_today>0
ORDER BY p.path;

